        const statusArray = Array.isArray(filters.status) ? filters.status : [filters.status];
        const filtered = components.filter((c) =>
          statusArray.includes(c.status as ComponentStatus)
        );

        expect(filtered.length).toBe(2);
      });

      test('should filter components with current train', () => {
        const components = [
          { id: '1', currentTrainId: 'train-A' },
          { id: '2', currentTrainId: null },
          { id: '3', currentTrainId: 'train-B' },
          { id: '4', currentTrainId: null },
        ];

        const filters: ComponentListFilters = { hasCurrentTrain: true };
        const filtered = components.filter((c) =>
          filters.hasCurrentTrain ? c.currentTrainId !== null : c.currentTrainId === null
        );

        expect(filtered.length).toBe(2);
        expect(filtered.every((c) => c.currentTrainId !== null)).toBe(true);
      });

      test('should filter spare components (no current train)', () => {
        const components = [
          { id: '1', currentTrainId: 'train-A' },
          { id: '2', currentTrainId: null },
          { id: '3', currentTrainId: 'train-B' },
          { id: '4', currentTrainId: null },
        ];

        const filters: ComponentListFilters = { hasCurrentTrain: false };
        const filtered = components.filter((c) =>
          filters.hasCurrentTrain === false ? c.currentTrainId === null : true
        );

        expect(filtered.length).toBe(2);
        expect(filtered.every((c) => c.currentTrainId === null)).toBe(true);
      });
    });

    describe('Train Components Query', () => {
      test('should list all components on a train', () => {
        const trainId = 'train-123';
        const allComponents = [
          { id: '1', currentTrainId: 'train-123', componentType: 'BOGIE', currentPosition: 'CAR_1_BOGIE_A' },
          { id: '2', currentTrainId: 'train-123', componentType: 'BOGIE', currentPosition: 'CAR_1_BOGIE_B' },
          { id: '3', currentTrainId: 'train-456', componentType: 'BOGIE', currentPosition: 'CAR_1_BOGIE_A' },
          { id: '4', currentTrainId: null, componentType: 'BOGIE', currentPosition: null },
        ];

        const trainComponents = allComponents.filter((c) => c.currentTrainId === trainId);

        expect(trainComponents.length).toBe(2);
        expect(trainComponents.every((c) => c.currentTrainId === trainId)).toBe(true);
      });

      test('should sort components by type and position', () => {
        const components = [
          { componentType: 'TRACTION_MOTOR', currentPosition: 'CAR_2_MOTOR_L' },
          { componentType: 'BOGIE', currentPosition: 'CAR_1_BOGIE_B' },
          { componentType: 'BOGIE', currentPosition: 'CAR_1_BOGIE_A' },
          { componentType: 'TRACTION_MOTOR', currentPosition: 'CAR_1_MOTOR_R' },
        ];

        const sorted = [...components].sort((a, b) => {
          const typeCompare = a.componentType.localeCompare(b.componentType);
          if (typeCompare !== 0) return typeCompare;
          return (a.currentPosition ?? '').localeCompare(b.currentPosition ?? '');
        });

        expect(sorted[0].componentType).toBe('BOGIE');
        expect(sorted[0].currentPosition).toBe('CAR_1_BOGIE_A');
        expect(sorted[1].currentPosition).toBe('CAR_1_BOGIE_B');
        expect(sorted[2].componentType).toBe('TRACTION_MOTOR');
      });
    });
  });
});
